vector<int> calculateStockSpan(vector<int>& prices) {
    stack<pair<int,int>> st; // {price, span}
    vector<int> span;

    for (int price : prices) {
        int currSpan = 1;
        while (!st.empty() && st.top().first <= price) {
            currSpan += st.top().second;
            st.pop();
        }
        st.push({price, currSpan});
        span.push_back(currSpan);
    }
    return span;
}

