code.C:
int* calculateStockSpan(int prices[], int n) {
    static int span[100000];
    int stackPrice[n], stackSpan[n];
    int top = -1;

    for (int i = 0; i < n; i++) {
        int currSpan = 1;

        while (top >= 0 && stackPrice[top] <= prices[i]) {
            currSpan += stackSpan[top];
            top--;
        }

        stackPrice[++top] = prices[i];
        stackSpan[top] = currSpan;
        span[i] = currSpan;
    }
    return span;
}

code.Java:
static int[] calculateStockSpan(int[] prices) {
    Stack<int[]> st = new Stack<>();
    int[] span = new int[prices.length];

    for (int i = 0; i < prices.length; i++) {
        int currSpan = 1;
        while (!st.isEmpty() && st.peek()[0] <= prices[i]) {
            currSpan += st.pop()[1];
        }
        st.push(new int[]{prices[i], currSpan});
        span[i] = currSpan;
    }
    return span;
}

