function calculateStockSpan(prices) {
    const stack = [];
    const span = [];

    for (let price of prices) {
        let currSpan = 1;
        while (stack.length && stack[stack.length - 1][0] <= price) {
            currSpan += stack.pop()[1];
        }
        stack.push([price, currSpan]);
        span.push(currSpan);
    }
    return span;
}
